'use strict';

/**
* Replace single-precision floating-point strided array elements not equal to a provided search element with a specified scalar constant.
*
* @module @stdlib/blas-ext-base-sfill-not-equal
*
* @example
* var Float32Array = require( '@stdlib/array-float32' );
* var sfillNotEqual = require( '@stdlib/blas-ext-base-sfill-not-equal' );
*
* var x = new Float32Array( [ 0.0, -2.0, 3.0, 0.0, 4.0, -6.0 ] );
*
* sfillNotEqual( 6, 0.0, 5.0, x, 1 );
* // x => <Float32Array>[ 0.0, 5.0, 5.0, 0.0, 5.0, 5.0 ]
*
* @example
* var Float32Array = require( '@stdlib/array-float32' );
* var sfillNotEqual = require( '@stdlib/blas-ext-base-sfill-not-equal' );
*
* var x = new Float32Array( [ 0.0, -2.0, 3.0, 0.0, 4.0, -6.0 ] );
*
* sfillNotEqual.ndarray( 6, 0.0, 5.0, x, 1, 0 );
* // x => <Float32Array>[ 0.0, 5.0, 5.0, 0.0, 5.0, 5.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
var tryRequire = require( '@stdlib/utils-try-require' );
var isError = require( '@stdlib/assert-is-error' );
var main = require( './main.js' );


// MAIN //

var sfillNotEqual;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	sfillNotEqual = main;
} else {
	sfillNotEqual = tmp;
}


// EXPORTS //

module.exports = sfillNotEqual;

// exports: { "ndarray": "sfillNotEqual.ndarray" }
